import{_ as a,o as s,c as i,ai as t}from"./chunks/framework.CsYGeNYI.js";const u=JSON.parse('{"title":"Doctor","description":"","frontmatter":{"summary":"Doctor command: health checks, config migrations, and repair steps","read_when":["Adding or modifying doctor migrations","Introducing breaking config changes"],"title":"Doctor"},"headers":[],"relativePath":"gateway/doctor.md","filePath":"gateway/doctor.md","lastUpdated":null}'),o={name:"gateway/doctor.md"};function n(r,e,d,l,c,h){return s(),i("div",null,[...e[0]||(e[0]=[t('<h1 id="doctor" tabindex="-1"><a class="header-anchor" href="#doctor">#</a> Doctor</h1><p><code>opensoul doctor</code> is the repair + migration tool for OpenSoul. It fixes stale config/state, checks health, and provides actionable repair steps.</p><h2 id="quick-start" tabindex="-1"><a class="header-anchor" href="#quick-start">#</a> Quick start</h2><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> doctor</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="headless-automation" tabindex="-1"><a class="header-anchor" href="#headless-automation">#</a> Headless / automation</h3><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> doctor</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --yes</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Accept defaults without prompting (including restart/service/sandbox repair steps when applicable).</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> doctor</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --repair</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Apply recommended repairs without prompting (repairs + restarts where safe).</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> doctor</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --repair</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --force</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Apply aggressive repairs too (overwrites custom supervisor configs).</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> doctor</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --non-interactive</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Run without prompts and only apply safe migrations (config normalization + on-disk state moves). Skips restart/service/sandbox actions that require human confirmation. Legacy state migrations run automatically when detected.</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> doctor</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --deep</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Scan system services for extra gateway installs (launchd/systemd/schtasks).</p><p>If you want to review changes before writing, open the config file first:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cat</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.opensoul/opensoul.json</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="what-it-does-summary" tabindex="-1"><a class="header-anchor" href="#what-it-does-summary">#</a> What it does (summary)</h2><ul><li>Optional pre-flight update for git installs (interactive only).</li><li>UI protocol freshness check (rebuilds Control UI when the protocol schema is newer).</li><li>Health check + restart prompt.</li><li>Skills status summary (eligible/missing/blocked).</li><li>Config normalization for legacy values.</li><li>OpenCode Zen provider override warnings (<code>models.providers.opencode</code>).</li><li>Legacy on-disk state migration (sessions/agent dir/WhatsApp auth).</li><li>State integrity and permissions checks (sessions, transcripts, state dir).</li><li>Config file permission checks (chmod 600) when running locally.</li><li>Model auth health: checks OAuth expiry, can refresh expiring tokens, and reports auth-profile cooldown/disabled states.</li><li>Extra workspace dir detection (<code>~/opensoul</code>).</li><li>Sandbox image repair when sandboxing is enabled.</li><li>Legacy service migration and extra gateway detection.</li><li>Gateway runtime checks (service installed but not running; cached launchd label).</li><li>Channel status warnings (probed from the running gateway).</li><li>Supervisor config audit (launchd/systemd/schtasks) with optional repair.</li><li>Gateway runtime best-practice checks (Node vs Bun, version-manager paths).</li><li>Gateway port collision diagnostics (default <code>18789</code>).</li><li>Security warnings for open DM policies.</li><li>Gateway auth warnings when no <code>gateway.auth.token</code> is set (local mode; offers token generation).</li><li>systemd linger check on Linux.</li><li>Source install checks (pnpm workspace mismatch, missing UI assets, missing tsx binary).</li><li>Writes updated config + wizard metadata.</li></ul><h2 id="detailed-behavior-and-rationale" tabindex="-1"><a class="header-anchor" href="#detailed-behavior-and-rationale">#</a> Detailed behavior and rationale</h2><h3 id="_0-optional-update-git-installs" tabindex="-1"><a class="header-anchor" href="#_0-optional-update-git-installs">#</a> 0) Optional update (git installs)</h3><p>If this is a git checkout and doctor is running interactively, it offers to update (fetch/rebase/build) before running doctor.</p><h3 id="_1-config-normalization" tabindex="-1"><a class="header-anchor" href="#_1-config-normalization">#</a> 1) Config normalization</h3><p>If the config contains legacy value shapes (for example <code>messages.ackReaction</code> without a channel-specific override), doctor normalizes them into the current schema.</p><h3 id="_2-legacy-config-key-migrations" tabindex="-1"><a class="header-anchor" href="#_2-legacy-config-key-migrations">#</a> 2) Legacy config key migrations</h3><p>When the config contains deprecated keys, other commands refuse to run and ask you to run <code>opensoul doctor</code>.</p><p>Doctor will:</p><ul><li>Explain which legacy keys were found.</li><li>Show the migration it applied.</li><li>Rewrite <code>~/.opensoul/opensoul.json</code> with the updated schema.</li></ul><p>The Gateway also auto-runs doctor migrations on startup when it detects a legacy config format, so stale configs are repaired without manual intervention.</p><p>Current migrations:</p><ul><li><code>routing.allowFrom</code> → <code>channels.whatsapp.allowFrom</code></li><li><code>routing.groupChat.requireMention</code> → <code>channels.whatsapp/telegram/imessage.groups.&quot;*&quot;.requireMention</code></li><li><code>routing.groupChat.historyLimit</code> → <code>messages.groupChat.historyLimit</code></li><li><code>routing.groupChat.mentionPatterns</code> → <code>messages.groupChat.mentionPatterns</code></li><li><code>routing.queue</code> → <code>messages.queue</code></li><li><code>routing.bindings</code> → top-level <code>bindings</code></li><li><code>routing.agents</code>/<code>routing.defaultAgentId</code> → <code>agents.list</code> + <code>agents.list[].default</code></li><li><code>routing.agentToAgent</code> → <code>tools.agentToAgent</code></li><li><code>routing.transcribeAudio</code> → <code>tools.media.audio.models</code></li><li><code>bindings[].match.accountID</code> → <code>bindings[].match.accountId</code></li><li><code>identity</code> → <code>agents.list[].identity</code></li><li><code>agent.*</code> → <code>agents.defaults</code> + <code>tools.*</code> (tools/elevated/exec/sandbox/subagents)</li><li><code>agent.model</code>/<code>allowedModels</code>/<code>modelAliases</code>/<code>modelFallbacks</code>/<code>imageModelFallbacks</code> → <code>agents.defaults.models</code> + <code>agents.defaults.model.primary/fallbacks</code> + <code>agents.defaults.imageModel.primary/fallbacks</code></li></ul><h3 id="_2b-opencode-zen-provider-overrides" tabindex="-1"><a class="header-anchor" href="#_2b-opencode-zen-provider-overrides">#</a> 2b) OpenCode Zen provider overrides</h3><p>If you’ve added <code>models.providers.opencode</code> (or <code>opencode-zen</code>) manually, it overrides the built-in OpenCode Zen catalog from <code>@mariozechner/pi-ai</code>. That can force every model onto a single API or zero out costs. Doctor warns so you can remove the override and restore per-model API routing + costs.</p><h3 id="_3-legacy-state-migrations-disk-layout" tabindex="-1"><a class="header-anchor" href="#_3-legacy-state-migrations-disk-layout">#</a> 3) Legacy state migrations (disk layout)</h3><p>Doctor can migrate older on-disk layouts into the current structure:</p><ul><li>Sessions store + transcripts: <ul><li>from <code>~/.opensoul/sessions/</code> to <code>~/.opensoul/agents/&lt;agentId&gt;/sessions/</code></li></ul></li><li>Agent dir: <ul><li>from <code>~/.opensoul/agent/</code> to <code>~/.opensoul/agents/&lt;agentId&gt;/agent/</code></li></ul></li><li>WhatsApp auth state (Baileys): <ul><li>from legacy <code>~/.opensoul/credentials/*.json</code> (except <code>oauth.json</code>)</li><li>to <code>~/.opensoul/credentials/whatsapp/&lt;accountId&gt;/...</code> (default account id: <code>default</code>)</li></ul></li></ul><p>These migrations are best-effort and idempotent; doctor will emit warnings when it leaves any legacy folders behind as backups. The Gateway/CLI also auto-migrates the legacy sessions + agent dir on startup so history/auth/models land in the per-agent path without a manual doctor run. WhatsApp auth is intentionally only migrated via <code>opensoul doctor</code>.</p><h3 id="_4-state-integrity-checks-session-persistence-routing-and-safety" tabindex="-1"><a class="header-anchor" href="#_4-state-integrity-checks-session-persistence-routing-and-safety">#</a> 4) State integrity checks (session persistence, routing, and safety)</h3><p>The state directory is the operational brainstem. If it vanishes, you lose sessions, credentials, logs, and config (unless you have backups elsewhere).</p><p>Doctor checks:</p><ul><li><strong>State dir missing</strong>: warns about catastrophic state loss, prompts to recreate the directory, and reminds you that it cannot recover missing data.</li><li><strong>State dir permissions</strong>: verifies writability; offers to repair permissions (and emits a <code>chown</code> hint when owner/group mismatch is detected).</li><li><strong>Session dirs missing</strong>: <code>sessions/</code> and the session store directory are required to persist history and avoid <code>ENOENT</code> crashes.</li><li><strong>Transcript mismatch</strong>: warns when recent session entries have missing transcript files.</li><li><strong>Main session “1-line JSONL”</strong>: flags when the main transcript has only one line (history is not accumulating).</li><li><strong>Multiple state dirs</strong>: warns when multiple <code>~/.opensoul</code> folders exist across home directories or when <code>OPENSOUL_STATE_DIR</code> points elsewhere (history can split between installs).</li><li><strong>Remote mode reminder</strong>: if <code>gateway.mode=remote</code>, doctor reminds you to run it on the remote host (the state lives there).</li><li><strong>Config file permissions</strong>: warns if <code>~/.opensoul/opensoul.json</code> is group/world readable and offers to tighten to <code>600</code>.</li></ul><h3 id="_5-model-auth-health-oauth-expiry" tabindex="-1"><a class="header-anchor" href="#_5-model-auth-health-oauth-expiry">#</a> 5) Model auth health (OAuth expiry)</h3><p>Doctor inspects OAuth profiles in the auth store, warns when tokens are expiring/expired, and can refresh them when safe. If the Anthropic Claude Code profile is stale, it suggests running <code>claude setup-token</code> (or pasting a setup-token). Refresh prompts only appear when running interactively (TTY); <code>--non-interactive</code> skips refresh attempts.</p><p>Doctor also reports auth profiles that are temporarily unusable due to:</p><ul><li>short cooldowns (rate limits/timeouts/auth failures)</li><li>longer disables (billing/credit failures)</li></ul><h3 id="_6-hooks-model-validation" tabindex="-1"><a class="header-anchor" href="#_6-hooks-model-validation">#</a> 6) Hooks model validation</h3><p>If <code>hooks.gmail.model</code> is set, doctor validates the model reference against the catalog and allowlist and warns when it won’t resolve or is disallowed.</p><h3 id="_7-sandbox-image-repair" tabindex="-1"><a class="header-anchor" href="#_7-sandbox-image-repair">#</a> 7) Sandbox image repair</h3><p>When sandboxing is enabled, doctor checks Docker images and offers to build or switch to legacy names if the current image is missing.</p><h3 id="_8-gateway-service-migrations-and-cleanup-hints" tabindex="-1"><a class="header-anchor" href="#_8-gateway-service-migrations-and-cleanup-hints">#</a> 8) Gateway service migrations and cleanup hints</h3><p>Doctor detects legacy gateway services (launchd/systemd/schtasks) and offers to remove them and install the OpenSoul service using the current gateway port. It can also scan for extra gateway-like services and print cleanup hints. Profile-named OpenSoul gateway services are considered first-class and are not flagged as &quot;extra.&quot;</p><h3 id="_9-security-warnings" tabindex="-1"><a class="header-anchor" href="#_9-security-warnings">#</a> 9) Security warnings</h3><p>Doctor emits warnings when a provider is open to DMs without an allowlist, or when a policy is configured in a dangerous way.</p><h3 id="_10-systemd-linger-linux" tabindex="-1"><a class="header-anchor" href="#_10-systemd-linger-linux">#</a> 10) systemd linger (Linux)</h3><p>If running as a systemd user service, doctor ensures lingering is enabled so the gateway stays alive after logout.</p><h3 id="_11-skills-status" tabindex="-1"><a class="header-anchor" href="#_11-skills-status">#</a> 11) Skills status</h3><p>Doctor prints a quick summary of eligible/missing/blocked skills for the current workspace.</p><h3 id="_12-gateway-auth-checks-local-token" tabindex="-1"><a class="header-anchor" href="#_12-gateway-auth-checks-local-token">#</a> 12) Gateway auth checks (local token)</h3><p>Doctor warns when <code>gateway.auth</code> is missing on a local gateway and offers to generate a token. Use <code>opensoul doctor --generate-gateway-token</code> to force token creation in automation.</p><h3 id="_13-gateway-health-check-restart" tabindex="-1"><a class="header-anchor" href="#_13-gateway-health-check-restart">#</a> 13) Gateway health check + restart</h3><p>Doctor runs a health check and offers to restart the gateway when it looks unhealthy.</p><h3 id="_14-channel-status-warnings" tabindex="-1"><a class="header-anchor" href="#_14-channel-status-warnings">#</a> 14) Channel status warnings</h3><p>If the gateway is healthy, doctor runs a channel status probe and reports warnings with suggested fixes.</p><h3 id="_15-supervisor-config-audit-repair" tabindex="-1"><a class="header-anchor" href="#_15-supervisor-config-audit-repair">#</a> 15) Supervisor config audit + repair</h3><p>Doctor checks the installed supervisor config (launchd/systemd/schtasks) for missing or outdated defaults (e.g., systemd network-online dependencies and restart delay). When it finds a mismatch, it recommends an update and can rewrite the service file/task to the current defaults.</p><p>Notes:</p><ul><li><code>opensoul doctor</code> prompts before rewriting supervisor config.</li><li><code>opensoul doctor --yes</code> accepts the default repair prompts.</li><li><code>opensoul doctor --repair</code> applies recommended fixes without prompts.</li><li><code>opensoul doctor --repair --force</code> overwrites custom supervisor configs.</li><li>You can always force a full rewrite via <code>opensoul gateway install --force</code>.</li></ul><h3 id="_16-gateway-runtime-port-diagnostics" tabindex="-1"><a class="header-anchor" href="#_16-gateway-runtime-port-diagnostics">#</a> 16) Gateway runtime + port diagnostics</h3><p>Doctor inspects the service runtime (PID, last exit status) and warns when the service is installed but not actually running. It also checks for port collisions on the gateway port (default <code>18789</code>) and reports likely causes (gateway already running, SSH tunnel).</p><h3 id="_17-gateway-runtime-best-practices" tabindex="-1"><a class="header-anchor" href="#_17-gateway-runtime-best-practices">#</a> 17) Gateway runtime best practices</h3><p>Doctor warns when the gateway service runs on Bun or a version-managed Node path (<code>nvm</code>, <code>fnm</code>, <code>volta</code>, <code>asdf</code>, etc.). WhatsApp + Telegram channels require Node, and version-manager paths can break after upgrades because the service does not load your shell init. Doctor offers to migrate to a system Node install when available (Homebrew/apt/choco).</p><h3 id="_18-config-write-wizard-metadata" tabindex="-1"><a class="header-anchor" href="#_18-config-write-wizard-metadata">#</a> 18) Config write + wizard metadata</h3><p>Doctor persists any config changes and stamps wizard metadata to record the doctor run.</p><h3 id="_19-workspace-tips-backup-memory-system" tabindex="-1"><a class="header-anchor" href="#_19-workspace-tips-backup-memory-system">#</a> 19) Workspace tips (backup + memory system)</h3><p>Doctor suggests a workspace memory system when missing and prints a backup tip if the workspace is not already under git.</p><p>See <a href="/docs/concepts/agent-workspace">/concepts/agent-workspace</a> for a full guide to workspace structure and git backup (recommended private GitHub or GitLab).</p>',76)])])}const g=a(o,[["render",n]]);export{u as __pageData,g as default};
